(window.webpackJsonp=window.webpackJsonp||[]).push([[4],{361:function(t,e){"use strict";e.__esModule=!0,e.default={render:function(){return this.$createElement("div",{staticClass:"theme-default-content content__default",domProps:{innerHTML:"<h1 id=\"成员\"><a href=\"#成员\" class=\"header-anchor\">#</a> 成员</h1>\n<h2 id=\"导师\"><a href=\"#导师\" class=\"header-anchor\">#</a> 导师</h2>\n<div class=\"row\"><div class=\"column\"><img src=\"/src/people/jiong%20zhang.jpg\" alt=\"Jiong Zhang\"> <a href=\"https://jiongzhang-john.github.io/\" target=\"_blank\" rel=\"noopener noreferrer\">张炯 / Jiong Zhang</a> <div>Co-director, Associate Professor</div> <a href=\"mailto:jiong.zhang@ieee.org\">jiong.zhang@ieee.org</a> <div><a href=\"https://scholar.google.com/citations?user=UJKsxKkAAAAJ&hl=en\" target=\"_blank\" rel=\"noopener noreferrer\">Google Scholar</a></div></div></div>\n<h2 id=\"研究团队\"><a href=\"#研究团队\" class=\"header-anchor\">#</a> 研究团队</h2>\n<p>MI² Lab 欢迎对眼科医学影像智能分析、基础模型与多模态大模型、眼-心-脑医学影像智能计算、多模态大模型与医学智能体、血管影像分析与智能诊疗、疾病标志物发现和可靠临床 AI 感兴趣的同学与合作者。</p>\n<h2 id=\"开放岗位\"><a href=\"#开放岗位\" class=\"header-anchor\">#</a> 开放岗位</h2>\n<ul><li>招收具有计算机、生物医学工程、医学影像、临床医学或相关背景的博士生、硕士生。</li><li>欢迎对眼科影像基础模型、多模态大模型、眼-心-脑多模态影像、医学智能体、血管影像分析和智能临床系统感兴趣的科研助理和实习生加入。</li><li>欢迎医院、影像中心和生命科学研究团队开展交叉合作。</li></ul>\n<p>课题组其他成员信息将在名单确认后继续更新。</p>"}})}}}}]);
